@pytest.mark.smoke
@pytest.mark.parametrize("scenario_case", _PARAM_CASES, ids=_PARAM_IDS)
def test_get_project_by_slug_smoke_success(
    api_client,
    auth_api_key_header: str,
    auth_api_key_query: str,
    config_test_data: Dict[str, Any],
    validator: SwaggerSchemaValidator,
    endpoint_spec_path: str,
    scenario_case: Dict[str, Any],
):
    """
    Smoke: GET /project/{project-slug} returns 200 and validates against the Project schema.
    Uses only required request data (path param) and available authentication.
    """

    if not _PARAM_CASES:
        pytest.skip(f"Test data file {TEST_DATA_FILENAME} not found or empty")

    # Merge default test data with scenario data, with scenario taking precedence
    case = _merge_test_data(config_test_data, scenario_case)

    # Required path parameter
    project_slug = case.get("project-slug") or ""
    if not isinstance(project_slug, str) or not project_slug.strip():
        pytest.skip("Required 'project-slug' not provided in config test_data or scenario ENDPOINT_TEST_DATA")

    # Use scenario's expected status code
    expected_status_code = case.get("statusCode")
    if expected_status_code is None:
        pytest.skip("Required 'statusCode' not provided in scenario ENDPOINT_TEST_DATA")

    # Build authentication
    ap = _build_headers_and_params(auth_api_key_header, auth_api_key_query)
    headers = ap["headers"]
    params = ap["params"]

    # Skip when no auth configured to avoid cross-cutting auth testing here
    if not headers and not params:
        pytest.skip("Authentication not configured (Circle-Token or circle-token not set)")

    # Request validation (path param presence/type)
    assert isinstance(project_slug, str) and project_slug, "project-slug must be a non-empty string"

    endpoint = _build_project_endpoint(project_slug)

    # Perform request
    resp = api_client.get(endpoint=endpoint, headers=headers, params=params)

    # Assert status code (from scenario case)
    assert resp.status_code == expected_status_code, f"Unexpected status code for slug '{project_slug}'"

    # Validate response schema via validator against spec for 200
    validation = validator.validate_schema_by_response(
        endpoint=endpoint_spec_path,
        method="get",
        status_code=str(expected_status_code),
        response=resp,
    )
    assert validation.get("valid"), f"Schema validation failed: {validation}"

    # Optionally assert returned slug matches request dynamically (no hardcoded values)
    try:
        body = resp.json()
        # Should match the canonical slug value
        assert "slug" in body and isinstance(body["slug"], str), "response must contain 'slug' as string"
        assert body["slug"] == project_slug, f"Returned slug mismatch for '{project_slug}'"
    except Exception:
        pytest.fail("Response JSON parsing failed or missing 'slug' field")


@pytest.mark.parametrize("scenario_case", _PARAM_CASES, ids=_PARAM_IDS)
def test_get_project_by_slug_with_url_escaped_slug_success(
    api_client,
    auth_api_key_header: str,
    auth_api_key_query: str,
    config_test_data: Dict[str, Any],
    validator: SwaggerSchemaValidator,
    endpoint_spec_path: str,
    scenario_case: Dict[str, Any],
):
    """
    Validate allowReserved behavior by URL-escaping '/' characters in the project slug.
    Confirms that the encoded slug still returns a valid 200 response per spec.
    """

    if not _PARAM_CASES:
        pytest.skip(f"Test data file {TEST_DATA_FILENAME} not found or empty")

    case = _merge_test_data(config_test_data, scenario_case)

    project_slug = case.get("project-slug") or ""
    if not isinstance(project_slug, str) or not project_slug.strip():
        pytest.skip("Required 'project-slug' not provided in config test_data or scenario ENDPOINT_TEST_DATA")

    expected_status_code = case.get("statusCode")
    if expected_status_code is None:
        pytest.skip("Required 'statusCode' not provided in scenario ENDPOINT_TEST_DATA")

    ap = _build_headers_and_params(auth_api_key_header, auth_api_key_query)
    headers = ap["headers"]
    params = ap["params"]
    if not headers and not params:
        pytest.skip("Authentication not configured (Circle-Token or circle-token not set)")

    # Encode slug including '/' characters; allowReserved implies server should accept encoded '/'
    encoded_slug = quote(project_slug, safe="")  # encode all reserved chars including '/'
    endpoint = _build_project_endpoint(encoded_slug)

    resp = api_client.get(endpoint=endpoint, headers=headers, params=params)
    assert resp.status_code == expected_status_code, f"Unexpected status code for encoded slug '{encoded_slug}'"

    validation = validator.validate_schema_by_response(
        endpoint=endpoint_spec_path,
        method="get",
        status_code=str(expected_status_code),
        response=resp,
    )
    assert validation.get("valid"), f"Schema validation failed for encoded slug: {validation}"

    # Compare returned slug to original (unencoded) project slug
    body = resp.json()
    assert "slug" in body and isinstance(body["slug"], str)
    assert body["slug"] == project_slug, "Encoded path should resolve to the same project"


